import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface Team {
  position: number;
  teamName: string;
  wins: number;
  losses: number;
  points: number;
}

interface LeagueData {
  league: string;
  season: string;
  topTeams: Team[];
}

export default function Widget() {
  const leagueData = response.data as LeagueData;
  const { league, season, topTeams } = leagueData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#263238' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              {league} Standings
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Season: {season}
            </Typography>
          </Box>
          <Stack spacing={1.5}>
            {topTeams.map((team) => (
              <Box key={team.position} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {team.position}. {team.teamName}
                </Typography>
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  W: {team.wins} - L: {team.losses} - Pts: {team.points}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
